const item = $input.first().json;

const channels = Array.isArray(item.channels) ? item.channels.join(', ') : (item.channels || 'linkedin');
const contentType = item.content_type || 'post';
const feedback = item.revision_feedback || '';
const assets = item.assets || '[]';

let userPrompt = `Przygotuj ${contentType} na kanaly: ${channels}.

Material zrodlowy:
${item.raw_text}`;

if (feedback) {
  userPrompt += `\n\nPoprawki od uzytkownika (zastosuj je):\n${feedback}`;
}

const systemPrompt = `Jestes doswiadczonym copywriterem marketingowym. Tworzysz angazujace tresci na social media.

NAJWAZNIEJSZA ZASADA: ZAWSZE generuj gotowa tresc posta. NIGDY nie pytaj o dodatkowe informacje, nie pros o doprecyzowanie, nie zadawaj pytan. Pracuj z tym co dostales - nawet jesli material zrodlowy jest krotki lub ogolny, stworz z niego najlepszy mozliwy post.

Zasady:
- Pisz po polsku, chyba ze uzytkownik wskaze inaczej
- Dostosuj ton i dlugosc do kanalu (LinkedIn = profesjonalny, max 3000 znakow; Facebook = luzniejszy; Instagram = krotki + hashtagi)
- Dodaj odpowiednie emoji i hashtagi jesli pasuja do kanalu
- Podaj TYLKO gotowa tresc posta - bez meta-komentarzy, bez "oto post", bez wyjasnien
- Jesli jest kilka kanalow, przygotuj osobna wersje dla kazdego, oddzielona naglowkiem kanalu`;

return [{ json: { systemPrompt, userPrompt, job_id: item.job_id, assets } }];

const item = $input.first().json;
const jobId = $('Build Prompt').first().json.job_id;
const assets = $('Build Prompt').first().json.assets || '[]';

return [{ json: {
  job_id: jobId,
  generated_text: item.text || item.output || JSON.stringify(item),
  assets
} }];

const item = $input.first();
const prevData = $('Format Output').first().json;
const text = prevData.generated_text || '';
const assetsRaw = prevData.assets || '[]';

// Parse assets to find user image
let userImageUrl = '';
try {
  const assets = typeof assetsRaw === 'string' ? JSON.parse(assetsRaw) : assetsRaw;
  const img = assets.find(a => a.kind === 'image' && a.url);
  if (img) userImageUrl = img.url;
} catch(e) {}

// Convert logo binary to base64
let logoDataUri = '';
if (item.binary && item.binary.data) {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  const mimeType = item.binary.data.mimeType || 'image/png';
  logoDataUri = `data:${mimeType};base64,${buf.toString('base64')}`;
}

const esc = s => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

let bodyHtml = esc(text)
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .replace(/^### (.*)$/gm, '<h3>$1</h3>')
  .replace(/^## (.*)$/gm, '<h2>$1</h2>')
  .replace(/^# (.*)$/gm, '<h1>$1</h1>')
  .replace(/(#\w+)/g, '<span class="cg-hashtag">$1</span>')
  .replace(/\n{2,}/g, '</p><p>')
  .replace(/\n/g, '<br/>');

bodyHtml = '<p>' + bodyHtml + '</p>';
bodyHtml = bodyHtml.replace(/<p><\/p>/g, '').replace(/<p>(<h[123]>)/g, '$1').replace(/(<\/h[123]>)<\/p>/g, '$1');

const logoImg = logoDataUri ? `<img class="cg-logo" src="${logoDataUri}" />` : '';
const userImg = userImageUrl ? `<div class="cg-user-image"><img src="${esc(userImageUrl)}" /></div>` : '';

const html = `<div class="cg-root cg-dark"><div class="cg-post-layout"><div class="cg-post-header">${logoImg}<span class="cg-kicker">Career Guide</span></div>${userImg}<div class="cg-post-body">${bodyHtml}</div><div class="cg-rule"></div></div></div>`;

const css = `@import url("https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap");:root{--cg-brand-primary:#4d96d9;--cg-brand-accent:#89c6eb;--cg-text-default:#1a1e32;--cg-text-muted:#667797;--cg-surface-page:#fcfcfe;--cg-matcher-cyan:#00acc1;--cg-matcher-purple:#8e44ad;--cg-matcher-pink:#d81b60}.cg-root.cg-dark{--cg-brand-primary:#8cb2e6;--cg-brand-accent:#a7dbff;--cg-text-default:#fbfbfd;--cg-text-muted:#a5afc8;--cg-surface-page:#161b2b;--cg-surface-card:#1e2439;--cg-border-default:#2f3b5c}*,*::before,*::after{box-sizing:border-box}html,body{margin:0;padding:0;width:100%;-webkit-font-smoothing:antialiased}body{font-family:"Inter",system-ui,sans-serif;font-size:18px;line-height:1.6;color:var(--cg-text-default);background:var(--cg-surface-page)}.cg-root{width:1200px;color:var(--cg-text-default);background:var(--cg-surface-page)}.cg-post-layout{width:100%;padding:56px 72px;display:flex;flex-direction:column;gap:24px}.cg-post-header{display:flex;align-items:center;gap:16px;margin-bottom:8px}.cg-logo{width:56px;height:auto}.cg-kicker{font-size:15px;font-weight:600;letter-spacing:0.1em;text-transform:uppercase;color:var(--cg-brand-primary)}.cg-user-image{width:100%;border-radius:16px;overflow:hidden;margin-bottom:8px}.cg-user-image img{width:100%;height:auto;display:block;border-radius:16px}.cg-post-body{font-size:20px;line-height:1.65;color:var(--cg-text-default)}.cg-post-body p{margin:0 0 16px}.cg-post-body strong{font-weight:700}.cg-post-body h1,.cg-post-body h2,.cg-post-body h3{margin:24px 0 12px;line-height:1.3}.cg-post-body h1{font-size:36px;font-weight:700}.cg-post-body h2{font-size:28px;font-weight:700}.cg-post-body h3{font-size:22px;font-weight:600}.cg-check{margin:4px 0;padding-left:4px}.cg-bullet{margin:4px 0;padding-left:16px}.cg-hashtag{color:var(--cg-brand-primary);font-weight:500}.cg-rule{height:4px;width:120px;border-radius:999px;background:linear-gradient(90deg,var(--cg-matcher-cyan),var(--cg-matcher-purple),var(--cg-matcher-pink));margin:16px 0 0}`;

return [{ json: {
  ...prevData,
  image_html: html,
  image_css: css
} }];

const imgItem = $input.first();
const prevData = $('Build Image HTML').first().json;

return [{ json: {
  job_id: prevData.job_id,
  generated_text: prevData.generated_text
}, binary: imgItem.binary }];

